# 역할 기반 접근 제어 (RBAC) 패턴

## 목표
사용자의 역할과 권한을 기반으로 리소스에 대한 접근을 제어하고, 데코레이터를 통해 간편하게 관리합니다.

## 언제 사용하는가
- 사용자 역할이 명확하게 정의된 시스템
- 역할 기반 권한 관리가 필요할 때
- 관리자, 사용자 등 역할이 구분될 때

## 언제 사용하지 않는가
- 매우 세분화된 권한 체계 (ABAC 고려)

## 핵심 구조

### Prisma 스키마

```prisma
// schema.prisma
enum UserRole {
  ADMIN
  MODERATOR
  USER
  GUEST
}

model User {
  id            String   @id @default(cuid())
  email         String   @unique
  password      String
  role          UserRole @default(USER)
  permissions   Permission[]
  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

model Permission {
  id    String @id @default(cuid())
  name  String @unique // 'users.read', 'posts.write', 등
  users User[]
}

model RolePermission {
  id           String   @id @default(cuid())
  role         UserRole
  permissionId String
  permission   Permission @relation(fields: [permissionId], references: [id])

  @@unique([role, permissionId])
}
```

### NestJS Guard 구현

```typescript
// auth/decorators/roles.decorator.ts
import { SetMetadata } from '@nestjs/common';
import { UserRole } from '@prisma/client';

export const ROLES_KEY = 'roles';
export const Roles = (...roles: UserRole[]) =>
  SetMetadata(ROLES_KEY, roles);

// auth/guards/roles.guard.ts
import {
  CanActivate,
  ExecutionContext,
  Injectable,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { UserRole } from '@prisma/client';
import { ROLES_KEY } from '../decorators/roles.decorator';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.getAllAndOverride<UserRole[]>(
      ROLES_KEY,
      [context.getHandler(), context.getClass()],
    );

    if (!requiredRoles) {
      // 역할 요구사항 없음 - 모든 인증된 사용자 허용
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const user = request.user; // JWT Guard에서 설정됨

    if (!user) {
      return false;
    }

    return requiredRoles.includes(user.role);
  }
}

// auth/guards/jwt.guard.ts
import {
  ExecutionContext,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';

@Injectable()
export class JwtGuard extends AuthGuard('jwt') {
  canActivate(context: ExecutionContext) {
    return super.canActivate(context);
  }

  handleRequest(err: any, user: any, info: any) {
    if (err || !user) {
      throw err || new UnauthorizedException();
    }
    return user;
  }
}
```

