# 청크 업로드 패턴

## 목표
대용량 파일을 작은 청크로 나누어 업로드하고, 실패 시 재개 가능하게 만들어 사용자 경험을 개선합니다.

## 언제 사용하는가
- 대용량 파일 업로드 (수백 MB 이상)
- 네트워크가 불안정한 환경
- 업로드 진행률 표시가 필요한 경우
- 실패 후 재개 기능이 필요한 경우

## 핵심 구조

### 클라이언트

```typescript
// upload/chunk-uploader.ts
interface ChunkUploadOptions {
  chunkSize?: number; // 청크 크기 (기본값: 5MB)
  maxRetries?: number; // 재시도 횟수
  onProgress?: (progress: UploadProgress) => void;
  onComplete?: () => void;
  onError?: (error: Error) => void;
}

interface UploadProgress {
  uploadId: string;
  totalChunks: number;
  completedChunks: number;
  percentage: number;
  bytesUploaded: number;
  bytesTotal: number;
}

export class ChunkUploader {
  private readonly DEFAULT_CHUNK_SIZE = 5 * 1024 * 1024; // 5MB
  private readonly DEFAULT_MAX_RETRIES = 3;

  async uploadFile(
    file: File,
    uploadUrl: string,
    options: ChunkUploadOptions = {},
  ): Promise<string> {
    const chunkSize = options.chunkSize || this.DEFAULT_CHUNK_SIZE;
    const maxRetries = options.maxRetries || this.DEFAULT_MAX_RETRIES;
    const totalChunks = Math.ceil(file.size / chunkSize);

    // 고유한 업로드 ID 생성
    const uploadId = this.generateUploadId(file);

    // 업로드된 청크 확인 (재개)
    const uploadedChunks = await this.getUploadedChunks(uploadId);

    let completedChunks = uploadedChunks.length;
    let bytesUploaded = completedChunks * chunkSize;

    // 이미 업로드된 부분 스킵
    for (let i = 0; i < totalChunks; i++) {
      if (uploadedChunks.includes(i)) {
        continue;
      }

      const start = i * chunkSize;
      const end = Math.min(start + chunkSize, file.size);
      const chunk = file.slice(start, end);

      try {
        await this.uploadChunk(
          chunk,
          uploadUrl,
          uploadId,
          i,
          totalChunks,
          maxRetries,
        );

        completedChunks++;
        bytesUploaded = completedChunks * chunkSize;

        // 진행률 업데이트
        if (options.onProgress) {
          options.onProgress({
            uploadId,
            totalChunks,
            completedChunks,
            percentage: (completedChunks / totalChunks) * 100,
            bytesUploaded,
            bytesTotal: file.size,
          });
        }
      } catch (error) {
        if (options.onError) {
          options.onError(error as Error);
        }
        throw error;
      }
    }

    // 업로드 완료
    if (options.onComplete) {
      options.onComplete();
    }

    return uploadId;
  }

  private async uploadChunk(
    chunk: Blob,
    uploadUrl: string,
    uploadId: string,
    chunkIndex: number,
    totalChunks: number,
    maxRetries: number,
  ): Promise<void> {
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        const formData = new FormData();
        formData.append('file', chunk);
        formData.append('uploadId', uploadId);
        formData.append('chunkIndex', String(chunkIndex));
        formData.append('totalChunks', String(totalChunks));

        const response = await fetch(uploadUrl, {
          method: 'POST',
          body: formData,
        });

        if (!response.ok) {
          throw new Error(`Upload chunk failed: ${response.statusText}`);
        }

        return;
      } catch (error) {
        if (attempt === maxRetries) {
          throw error;
        }

        // 지수 백오프
        const delay = 1000 * Math.pow(2, attempt);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }

  private async getUploadedChunks(uploadId: string): Promise<number[]> {
    try {
      const response = await fetch(`/api/uploads/${uploadId}/status`);
      if (response.ok) {
        const data = await response.json();
        return data.uploadedChunks || [];
      }
    } catch (error) {
      // 무시
    }
    return [];
  }

  private generateUploadId(file: File): string {
    return `${file.name}-${file.size}-${Date.now()}`;
  }
}
```

### React 컴포넌트

```typescript
// components/file-upload.tsx
import { useState } from 'react';
import { ChunkUploader, UploadProgress } from 'upload/chunk-uploader';

export function FileUploadComponent() {
  const [progress, setProgress] = useState<UploadProgress | null>(null);
  const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
  const [error, setError] = useState<string | null>(null);

  const uploader = new ChunkUploader();

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
