      await uploader.uploadFile(file, '/api/upload', {
        chunkSize: 5 * 1024 * 1024, // 5MB
        onProgress: setProgress,
        onComplete: () => setStatus('success'),
        onError: (err) => {
          setStatus('error');
          setError(err.message);
        },
      });
    } catch (err) {
      setStatus('error');
