# Presigned URL 패턴

## 목표
AWS S3 presigned URL을 활용하여 클라이언트가 서버를 거치지 않고 직접 파일을 업로드하여 서버 부하를 줄입니다.

## 언제 사용하는가
- 서버 부하를 최소화해야 할 때
- 클라이언트가 직접 클라우드 스토리지에 접근해야 할 때
- 임시 접근 권한이 필요한 경우
- 대규모 동시 업로드

## 핵심 구조

### 서버 - Presigned URL 생성

```typescript
// upload/upload.service.ts
import {
  S3Client,
  PutObjectCommand,
} from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { Injectable } from '@nestjs/common';

interface PresignedUrlRequest {
  fileName: string;
  fileType: string;
  fileSize: number;
}

interface PresignedUrlResponse {
  uploadUrl: string;
  fileKey: string;
  expiresIn: number;
}

@Injectable()
export class S3UploadService {
  private s3Client: S3Client;
  private readonly bucket = process.env.AWS_S3_BUCKET;
  private readonly region = process.env.AWS_REGION;

  constructor() {
    this.s3Client = new S3Client({ region: this.region });
  }

  async generatePresignedUrl(
    request: PresignedUrlRequest,
  ): Promise<PresignedUrlResponse> {
    // 파일 키 생성 (예: uploads/user-123/2024-01-01-filename.ext)
    const userId = 'user-123'; // 실제로는 요청 사용자에서 추출
    const timestamp = new Date().toISOString().split('T')[0];
    const fileKey = `uploads/${userId}/${timestamp}-${request.fileName}`;

    // 파일 크기 검증 (예: 100MB 제한)
    const MAX_FILE_SIZE = 100 * 1024 * 1024;
    if (request.fileSize > MAX_FILE_SIZE) {
      throw new BadRequestException(
        `File size exceeds ${MAX_FILE_SIZE / 1024 / 1024}MB limit`
      );
    }

    // 허용된 파일 타입 검증
    const allowedTypes = [
      'image/jpeg',
      'image/png',
      'image/gif',
      'application/pdf',
      'video/mp4',
    ];

    if (!allowedTypes.includes(request.fileType)) {
      throw new BadRequestException('File type not allowed');
    }

    const command = new PutObjectCommand({
      Bucket: this.bucket,
      Key: fileKey,
      ContentType: request.fileType,
      ContentLength: request.fileSize,
      // 서버에서만 업로드 가능하도록 메타데이터 추가
      Metadata: {
        uploadedAt: new Date().toISOString(),
        uploadedBy: userId,
      },
      // CORS를 위해 필요한 헤더
      ACL: 'private',
    });

    const expiresIn = 3600; // 1시간
    const uploadUrl = await getSignedUrl(this.s3Client, command, {
      expiresIn,
    });

    return {
      uploadUrl,
      fileKey,
      expiresIn,
    };
  }

  // 업로드 확인 (S3의 파일 존재 여부)
  async confirmUpload(fileKey: string): Promise<boolean> {
    try {
      const command = new HeadObjectCommand({
        Bucket: this.bucket,
        Key: fileKey,
      });

      await this.s3Client.send(command);
      return true;
    } catch (error) {
      return false;
    }
  }

  // 파일 URL 생성 (다운로드/조회용)
  async getFileUrl(fileKey: string): Promise<string> {
    const command = new GetObjectCommand({
      Bucket: this.bucket,
      Key: fileKey,
    });

    const expiresIn = 86400; // 24시간
    return getSignedUrl(this.s3Client, command, { expiresIn });
  }
}

// upload/upload.controller.ts
@Controller('api/uploads')
export class UploadController {
  constructor(private uploadService: S3UploadService) {}

  @Post('presigned-url')
  @UseGuards(JwtGuard)
  async getPresignedUrl(
    @Body() request: PresignedUrlRequest,
  ): Promise<PresignedUrlResponse> {
    return this.uploadService.generatePresignedUrl(request);
  }

  @Post('confirm')
  @UseGuards(JwtGuard)
  async confirmUpload(
    @Body() { fileKey }: { fileKey: string },
  ) {
    const exists = await this.uploadService.confirmUpload(fileKey);

    if (!exists) {
      throw new BadRequestException('File not found in storage');
    }

    // 데이터베이스에 파일 기록
    await this.prisma.file.create({
      data: {
        key: fileKey,
        userId: request.user.id,
        size: request.fileSize,
        type: request.fileType,
      },
    });

    return { success: true };
  }
}
```

### 클라이언트

```typescript
// upload/s3-uploader.ts
interface PresignedUrlRequest {
  fileName: string;
  fileType: string;
  fileSize: number;
}

interface UploadProgress {
  percentage: number;
  bytesUploaded: number;
  bytesTotal: number;
}

export class S3Uploader {
  private readonly API_BASE = process.env.REACT_APP_API_URL;

  async uploadFile(
    file: File,
    onProgress?: (progress: UploadProgress) => void,
  ): Promise<string> {
    // 1. Presigned URL 요청
    const presignedResponse = await fetch(
      `${this.API_BASE}/api/uploads/presigned-url`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fileName: file.name,
          fileType: file.type,
          fileSize: file.size,
        }),
        credentials: 'include',
      },
    );

    if (!presignedResponse.ok) {
      throw new Error('Failed to get presigned URL');
    }

    const { uploadUrl, fileKey } = await presignedResponse.json();

    // 2. 직접 S3에 업로드
    const xhr = new XMLHttpRequest();

    // 진행률 추적
    xhr.upload.addEventListener('progress', (e) => {
      if (e.lengthComputable && onProgress) {
        const percentComplete = (e.loaded / e.total) * 100;
        onProgress({
          percentage: percentComplete,
          bytesUploaded: e.loaded,
          bytesTotal: e.total,
        });
      }
    });

    // 오류 처리
    xhr.addEventListener('error', () => {
      throw new Error('Upload failed');
    });

    // 업로드 수행
    await new Promise((resolve, reject) => {
      xhr.onload = () => {
        if (xhr.status === 200) {
          resolve(null);
        } else {
          reject(new Error(`Upload failed with status ${xhr.status}`));
        }
      };
      xhr.onerror = () => reject(new Error('Upload error'));

      xhr.open('PUT', uploadUrl);
      xhr.setRequestHeader('Content-Type', file.type);
      xhr.send(file);
    });

    // 3. 서버에 업로드 확인
    await fetch(`${this.API_BASE}/api/uploads/confirm`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ fileKey }),
      credentials: 'include',
    });

    return fileKey;
  }
}
```

### React 컴포넌트

