  return fetch(presignedUrl, {
    method: 'PUT',
    body: file, // 검증 없음!
  });
}

// ✅ 좋은 예제
uploadFile(file) {
  if (file.size > MAX_SIZE) throw new Error('Too large');
  if (!ALLOWED_TYPES.includes(file.type)) throw new Error('Invalid type');

  return fetch(presignedUrl, {
    method: 'PUT',
    body: file,
  });
}
```

