---
id: F-07
title: JWT 토큰 문제 해결
pattern_id: P-07
error_ids: [E-19, E-20, E-21]
tech_scope: JWT, 토큰 관리, 보안
---

# JWT 토큰 문제 해결

JWT 토큰 생성, 검증, 갱신 과정에서 발생하는 문제를 해결합니다.

## 1단계: 증상 고정

- "Invalid signature" 오류
- "Token not found" 또는 토큰 누락
- 토큰이 시간이 지나도 유효함 (만료 체크 안 함)
- 토큰이 너무 빨리 만료됨
- 토큰 갱신 실패
- 클라이언트에서 토큰 저장 위치 불명확

## 2단계: 재현

```javascript
// ❌ 토큰 검증 미흡
const token = req.headers['authorization']?.split(' ')[1];

if (!token) {
  return res.status(401).json({ error: 'Token required' });
}

// 서명만 검증, 만료 시간은 검증 안 함
jwt.verify(token, process.env.SECRET); // 이미 jwt.verify가 만료를 확인함

// ❌ 토큰 저장 위치 불안전
localStorage.setItem('token', token); // XSS 공격에 취약

// ❌ 토큰 갱신 미흡
app.post('/api/auth/refresh', (req, res) => {
  const { refreshToken } = req.body;
  // 리프레시 토큰 검증 없음
  const newToken = jwt.sign({ userId: 1 }, SECRET, { expiresIn: '1h' });
  res.json({ token: newToken });
});
```

## 3단계: 범위 축소

JWT 문제의 유형:

1. **토큰 생성 오류**: 시크릿 키 오류, 옵션 설정 미흡
2. **토큰 검증 실패**: 서명 검증, 만료 확인 불충분
3. **토큰 저장 위치**: localStorage, sessionStorage, 쿠키 선택
4. **토큰 갱신**: 리프레시 토큰 없음, 갱신 로직 오류
5. **보안 문제**: XSS, CSRF, 토큰 노출

## 4단계: 증거 수집

```bash
# JWT 디코드 (서명 검증 없음)
npm install -g jwt-cli
jwt decode "eyJhbGc..."

# 토큰 내용 확인
echo "eyJhbGc..." | base64 -D | jq
```

```javascript
// JWT 검증 단계별 테스트
const jwt = require('jsonwebtoken');

const token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...';
const secret = process.env.JWT_SECRET;

try {
  const decoded = jwt.verify(token, secret);
  console.log('Token valid:', decoded);
} catch (error) {
  console.log('Token invalid:');
  console.log('- Name:', error.name);
  console.log('- Message:', error.message);

  if (error.name === 'TokenExpiredError') {
    console.log('- Expired at:', error.expiredAt);
  }
}

// 서명 검증만 (만료 무시)
const decoded = jwt.decode(token);
console.log('Decoded (unverified):', decoded);
```

## 5단계: 원인 후보 정렬

| 원인 | 확률 | 난도 |
|------|------|------|
| 잘못된 시크릿 키 | 매우높음 | 낮음 |
| 만료 시간 검증 누락 | 높음 | 낮음 |
| 토큰 저장 위치 부적절 | 높음 | 중간 |
| 리프레시 토큰 미구현 | 높음 | 중간 |
| 환경 변수 설정 오류 | 중간 | 낮음 |

## 6단계: 수정안 선택

### 수정안 1: JWT 생성 (권장)

```javascript
// authService.js
const jwt = require('jsonwebtoken');

class AuthService {
  // 액세스 토큰 생성 (수명 짧음)
  generateAccessToken(userId, email) {
    return jwt.sign(
      {
        userId,
        email,
        type: 'access'
      },
      process.env.JWT_SECRET,
      {
        expiresIn: '15m', // 15분
        algorithm: 'HS256',
        issuer: 'my-app',
        audience: 'my-app-users'
      }
    );
  }

  // 리프레시 토큰 생성 (수명 김)
  generateRefreshToken(userId) {
    return jwt.sign(
      {
        userId,
        type: 'refresh'
      },
      process.env.REFRESH_SECRET, // 다른 시크릿 키 사용
      {
        expiresIn: '7d', // 7일
        algorithm: 'HS256'
      }
    );
  }

  // 토큰 쌍 생성
  generateTokenPair(userId, email) {
    return {
      accessToken: this.generateAccessToken(userId, email),
      refreshToken: this.generateRefreshToken(userId),
      expiresIn: 15 * 60 // 초 단위
    };
  }

  // 토큰 검증
  verifyAccessToken(token) {
    try {
      return jwt.verify(token, process.env.JWT_SECRET, {
        issuer: 'my-app',
        audience: 'my-app-users'
      });
    } catch (error) {
      if (error.name === 'TokenExpiredError') {
        throw new Error('Token expired');
      }
      throw new Error('Invalid token');
    }
  }

  // 리프레시 토큰 검증
  verifyRefreshToken(token) {
    try {
      return jwt.verify(token, process.env.REFRESH_SECRET);
    } catch (error) {
      throw new Error('Invalid refresh token');
    }
  }
}

module.exports = new AuthService();
```

### 수정안 2: 토큰 저장 및 전송 (보안)

```javascript
// 옵션 1: HttpOnly 쿠키 (권장)
app.post('/api/auth/login', async (req, res) => {
  const user = await authenticate(req.body);
  const { accessToken, refreshToken } = generateTokenPair(user.id);

  // HttpOnly 쿠키에 저장 (자동 전송, XSS 보호)
  res.cookie('accessToken', accessToken, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000 // 15분
  });

  res.cookie('refreshToken', refreshToken, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 7 * 24 * 60 * 60 * 1000 // 7일
  });

  res.json({ success: true });
});

// 클라이언트: fetch할 때 credentials 포함
fetch('/api/protected', {
  credentials: 'include' // 쿠키 자동 전송
});

// 옵션 2: Memory + SessionStorage (XSS 위험)
// 액세스 토큰은 메모리 변수에, 리프레시는 sessionStorage에
let accessToken = null;

async function login(credentials) {
  const res = await fetch('/api/auth/login', {
    method: 'POST',
    body: JSON.stringify(credentials)
  });

  const { accessToken: token, refreshToken } = await res.json();

  accessToken = token; // 메모리에 저장
  sessionStorage.setItem('refreshToken', refreshToken);
}

// 옵션 3: LocalStorage (최악의 선택, XSS 노출)
// ⚠️ 피해야 할 방식
localStorage.setItem('accessToken', token);
```

### 수정안 3: 서버 미들웨어

```javascript
// authMiddleware.js
const authService = require('./authService');

const authenticateToken = (req, res, next) => {
  // 1. 쿠키 또는 Authorization 헤더에서 토큰 추출
  const token = req.cookies.accessToken ||
                req.headers['authorization']?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Token required' });
  }

  // 2. 토큰 검증
  try {
    const payload = authService.verifyAccessToken(token);
    req.user = payload;
    next();
  } catch (error) {
    if (error.message === 'Token expired') {
      // 토큰 갱신 자동 시도 (선택사항)
      return res.status(401).json({
        error: 'Token expired',
        code: 'TOKEN_EXPIRED'
      });
    }

    return res.status(401).json({ error: 'Invalid token' });
  }
};

module.exports = authenticateToken;
```

### 수정안 4: 토큰 갱신

```javascript
// authRouter.js
const express = require('express');
const authService = require('./authService');

const router = express.Router();

router.post('/refresh', (req, res) => {
  // 1. 리프레시 토큰 추출
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

  if (!refreshToken) {
    return res.status(401).json({ error: 'Refresh token required' });
  }

  // 2. 리프레시 토큰 검증
  try {
    const payload = authService.verifyRefreshToken(refreshToken);

    // 3. 데이터베이스에서 리프레시 토큰 확인 (옵션)
    // - 로그아웃 토큰 블랙리스트 확인
    // - 토큰 재사용 여부 확인

    // 4. 새 토큰 생성
    const user = await User.findById(payload.userId);
    const { accessToken, refreshToken: newRefreshToken } =
      authService.generateTokenPair(user.id, user.email);

    // 5. 새 쿠키 설정
    res.cookie('accessToken', accessToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 15 * 60 * 1000
    });

    res.cookie('refreshToken', newRefreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 7 * 24 * 60 * 60 * 1000
    });

    res.json({ accessToken, expiresIn: 15 * 60 });
  } catch (error) {
    return res.status(401).json({ error: 'Invalid refresh token' });
  }
});

router.post('/logout', (req, res) => {
  res.clearCookie('accessToken');
  res.clearCookie('refreshToken');

  // (선택사항) 리프레시 토큰 블랙리스트 추가
  // tokenBlacklist.add(req.body.refreshToken);

  res.json({ success: true });
});

module.exports = router;
```

### 수정안 5: 클라이언트 토큰 갱신

```javascript
// authClient.js
class AuthClient {
  constructor() {
    this.accessToken = null;
  }

  async fetchWithRefresh(url, options = {}) {
    let response = await fetch(url, {
      ...options,
      credentials: 'include' // 쿠키 전송
    });

    // 토큰 만료 시 갱신 시도
    if (response.status === 401) {
      const refreshed = await this.refreshToken();

      if (!refreshed) {
        // 갱신 실패 - 로그인 페이지로
        window.location.href = '/login';
        return;
      }

      // 원래 요청 재시도
      response = await fetch(url, {
        ...options,
        credentials: 'include'
      });
    }

    return response;
  }

  async refreshToken() {
    try {
      const response = await fetch('/api/auth/refresh', {
        method: 'POST',
        credentials: 'include'
      });

      if (!response.ok) {
        return false;
      }

      const { accessToken } = await response.json();
      this.accessToken = accessToken;
      return true;
    } catch (error) {
      console.error('Token refresh failed:', error);
      return false;
    }
  }

  async login(email, password) {
    const response = await fetch('/api/auth/login', {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password })
    });

    if (!response.ok) {
      throw new Error('Login failed');
    }

    const { accessToken } = await response.json();
    this.accessToken = accessToken;
  }

  async logout() {
    await fetch('/api/auth/logout', {
      method: 'POST',
      credentials: 'include'
    });

    this.accessToken = null;
    window.location.href = '/login';
  }
}

const authClient = new AuthClient();
```

## 7단계: 검증

```javascript
describe('JWT Token', () => {
  it('should create valid token', () => {
    const token = authService.generateAccessToken(1, 'user@test.com');
    expect(token).toBeDefined();

    const decoded = jwt.decode(token);
    expect(decoded.userId).toBe(1);
    expect(decoded.email).toBe('user@test.com');
  });

  it('should verify token with correct secret', () => {
    const token = authService.generateAccessToken(1, 'user@test.com');
    const decoded = authService.verifyAccessToken(token);

    expect(decoded.userId).toBe(1);
  });

  it('should reject token with wrong secret', () => {
    const token = jwt.sign({ userId: 1 }, 'wrong-secret');

    expect(() => {
      authService.verifyAccessToken(token);
    }).toThrow();
  });

  it('should reject expired token', (done) => {
    const token = jwt.sign({ userId: 1 }, process.env.JWT_SECRET, {
      expiresIn: '1ms'
    });

    setTimeout(() => {
      expect(() => {
        authService.verifyAccessToken(token);
      }).toThrow('Token expired');
      done();
    }, 10);
  });
});
```

## 8단계: 재발 방지

1. **환경 변수 설정**

```bash
# .env
JWT_SECRET=your-super-secret-key-min-32-chars
REFRESH_SECRET=your-refresh-secret-key-min-32-chars
```

2. **보안 체크리스트**
   - [ ] JWT_SECRET이 32자 이상인가?
   - [ ] 프로덕션에서 환경 변수로 관리하는가?
   - [ ] HttpOnly 쿠키 사용하는가?
   - [ ] 리프레시 토큰 만료 시간이 더 길다?
   - [ ] 토큰 갱신 끝점이 보호되어 있는가?

## 연결된 프롬프트 블록

- **PB-CL-08-jwt-structure**: JWT 구조 이해
- **PB-RP-07-token-generation**: 토큰 생성 테스트
- **PB-DG-08-token-decode**: 토큰 디코드 및 검증
- **PB-PA-08-token-refresh**: 토큰 갱신 로직
- **PB-VF-07-token-security**: 토큰 보안 검증

content.F-09:
---
id: F-09
title: N+1 쿼리 해결
pattern_id: P-09
error_ids: [E-25, E-26, E-27]
tech_scope: 데이터베이스 최적화, Prisma, SQL
---

# N+1 쿼리 해결

N+1 쿼리 문제로 인한 데이터베이스 성능 저하를 진단하고 해결합니다.

## 1단계: 증상 고정

증상:
- 데이터베이스 쿼리 수가 비정상적으로 많음
- 작은 데이터 조회에도 수백 개의 쿼리 발생
- 페이지 로드 시간이 오래 걸림
- 데이터베이스 CPU 사용률 높음
- 데이터 양이 늘어날수록 성능 급속 악화

## 2단계: 재현

```javascript
// ❌ N+1 쿼리 예제
const users = await prisma.user.findMany();

// 각 user마다 1번씩 쿼리 실행 = N개
for (const user of users) {
  const posts = await prisma.post.findMany({
    where: { authorId: user.id }
  });
  console.log(user.name, posts.length);
}

// 총 쿼리: 1 (users) + N (각 user의 posts) = N+1

// 또는 더 심한 경우
// ❌ 루프 내 루프
const users = await prisma.user.findMany();

for (const user of users) {
  const posts = await prisma.post.findMany({
    where: { authorId: user.id }
  });

  for (const post of posts) {
    const comments = await prisma.comment.findMany({
      where: { postId: post.id }
    });
    // 총 쿼리: 1 + N + (N * M)
  }
}
```

## 3단계: 범위 축소

N+1 문제의 유형:

1. **루프 내 쿼리**: 반복문에서 매번 쿼리 실행
2. **관계 데이터 로딩**: 1:N 또는 M:N 관계에서 개별 조회
3. **중첩 관계**: 여러 수준의 관계 데이터 조회
4. **이터레이터 메서드**: map, forEach 등에서 비동기 쿼리
5. **GraphQL Resolver**: 각 필드마다 개별 쿼리

## 4단계: 증거 수집

```bash
# Prisma 쿼리 로깅 활성화
export DATABASE_URL="postgresql://...?logging=true"

# 또는 코드에서
const prisma = new PrismaClient({
  log: ['query', 'error', 'warn']
});
```

```javascript
// 쿼리 실행 로깅
prisma.$on('query', (e) => {
  console.log('Query:', e.query);
  console.log('Duration:', e.duration, 'ms');
});

// 또는 더 상세하게
const startTime = Date.now();
await queryFunction();
console.log(`Execution time: ${Date.now() - startTime}ms`);
```

## 5단계: 원인 후보 정렬

| 원인 | 확률 | 복잡도 |
|------|------|--------|
| 루프 내 쿼리 | 매우높음 | 낮음 |
| 관계 미선택 로딩 | 높음 | 중간 |
| include 누락 | 높음 | 낮음 |
| 깊은 중첩 | 중간 | 높음 |
| GraphQL 문제 | 낮음 | 높음 |

## 6단계: 수정안 선택

### 수정안 1: Prisma include (권장)

```javascript
// ❌ N+1 쿼리
const users = await prisma.user.findMany();
for (const user of users) {
  user.posts = await prisma.post.findMany({
    where: { authorId: user.id }
  });
}

// ✅ include로 한 번에 로드
const users = await prisma.user.findMany({
  include: {
    posts: true
  }
});

// 각 user에는 posts 배열이 이미 포함됨
console.log(users[0].posts); // 추가 쿼리 없음

// ✅ 중첩 include
const users = await prisma.user.findMany({
  include: {
    posts: {
      include: {
        comments: true
      }
    }
  }
});

// ✅ 조건부 include
const users = await prisma.user.findMany({
  include: {
    posts: {
      where: { published: true },
      orderBy: { createdAt: 'desc' },
      take: 5
    }
  }
});
```

### 수정안 2: select로 필요한 필드만 로드

```javascript
// ✅ 필요한 필드만 선택
const users = await prisma.user.findMany({
  select: {
    id: true,
    name: true,
    email: true,
    posts: {
      select: {
        id: true,
        title: true
      }
    }
  }
});

// 또는 exclude 사용
const users = await prisma.user.findMany({
  select: {
    id: true,
    name: true,
    email: true,
    password: false // 제외
  }
});
```

### 수정안 3: 배치 로딩

```javascript
// ❌ 배치 로딩 없음
async function getUsersWithPostCounts() {
  const users = await prisma.user.findMany();

  for (const user of users) {
    user.postCount = await prisma.post.count({
      where: { authorId: user.id }
    });
  }

  return users;
}

// ✅ 배치 로딩 (한 번에)
async function getUsersWithPostCounts() {
  const users = await prisma.user.findMany();

  const postCounts = await prisma.post.groupBy({
    by: ['authorId'],
    _count: {
      id: true
    }
  });

  const countMap = Object.fromEntries(
    postCounts.map(c => [c.authorId, c._count.id])
  );

  return users.map(user => ({
    ...user,
    postCount: countMap[user.id] || 0
  }));
}
```

### 수정안 4: raw SQL 쿼리

```javascript
// 매우 복잡한 조회는 SQL이 더 효율적
const result = await prisma.$queryRaw`
  SELECT
    u.id,
    u.name,
    COUNT(p.id) as post_count,
    JSON_AGG(JSON_BUILD_OBJECT(
      'id', p.id,
      'title', p.title
    )) as posts
  FROM users u
  LEFT JOIN posts p ON p.author_id = u.id
  GROUP BY u.id
`;

// 또는 parameterized query
const result = await prisma.$queryRaw`
  SELECT u.*, COUNT(p.id) as post_count
  FROM users u
  LEFT JOIN posts p ON p.author_id = u.id
  WHERE u.id = ${userId}
  GROUP BY u.id
`;
```

### 수정안 5: DataLoader (GraphQL)

```javascript
// DataLoader로 배치 처리
const DataLoader = require('dataloader');

const postLoader = new DataLoader(async (userIds) => {
  const posts = await prisma.post.findMany({
    where: {
      authorId: { in: userIds }
    }
  });

  // userIds 순서대로 결과 반환
  return userIds.map(userId =>
    posts.filter(p => p.authorId === userId)
  );
});

// GraphQL Resolver에서 사용
const User = {
  posts(user, args, context) {
    return postLoader.load(user.id); // 배치 처리됨
  }
};

// 클라이언트 요청 내에서 여러 번 호출해도 한 번의 쿼리로 처리
```

### 수정안 6: Redis 캐싱

```javascript
const redis = require('redis').createClient();

async function getUsersWithPosts(userId) {
  // 캐시 확인
  const cached = await redis.get(`user:${userId}:posts`);
  if (cached) {
    return JSON.parse(cached);
  }

  // 데이터베이스에서 로드
  const user = await prisma.user.findUnique({
    where: { id: userId },
    include: { posts: true }
  });

  // 캐시 저장 (1시간)
  await redis.setex(
    `user:${userId}:posts`,
    3600,
    JSON.stringify(user)
  );

  return user;
}
```

## 7단계: 검증

```javascript
describe('N+1 Query Prevention', () => {
  it('should load users with posts in minimum queries', async () => {
    let queryCount = 0;

    prisma.$on('query', () => {
      queryCount++;
    });

    // 10명의 사용자와 그들의 게시글 조회
    const users = await prisma.user.findMany({
      take: 10,
      include: { posts: true }
    });

    // 예상: 1개 쿼리 (또는 매우 적은 수)
    expect(queryCount).toBeLessThan(5);
    expect(users).toHaveLength(10);
    expect(users[0].posts).toBeDefined();
  });

  it('should not query in loop', async () => {
    // ❌ 안 좋은 패턴
    const users = await prisma.user.findMany();
    for (const user of users) {
      const posts = await prisma.post.findMany({
        where: { authorId: user.id }
      });
      // N+1 쿼리 발생
    }

    // ✅ 좋은 패턴
    const usersWithPosts = await prisma.user.findMany({
      include: { posts: true }
    });
  });
});
```

## 8단계: 재발 방지

1. **쿼리 로깅**

```javascript
// development에서 항상 로깅
const prisma = new PrismaClient({
  log: process.env.NODE_ENV === 'development'
    ? ['query', 'error', 'warn']
    : ['error']
});
```

2. **성능 모니터링**

```javascript
import * as Sentry from "@sentry/node";

prisma.$on('query', (e) => {
  if (e.duration > 1000) {
    Sentry.captureMessage(
      `Slow query: ${e.query}`,
      'warning'
    );
  }
});
```

3. **코드 리뷰 체크리스트**
   - [ ] 루프에서 쿼리 실행하지 않는가?
   - [ ] include/select 사용하는가?
   - [ ] 필요한 필드만 로드하는가?
   - [ ] 중복 쿼리는 없는가?

## 연결된 프롬프트 블록

- **PB-CL-10-query-optimization**: 쿼리 최적화
- **PB-RP-09-query-profiling**: 쿼리 프로파일링
- **PB-DG-10-slow-queries**: 느린 쿼리 진단
- **PB-PA-10-query-batching**: 쿼리 배치 처리
- **PB-VF-09-performance-test**: 성능 테스트

content.F-10:
---
id: F-10
title: 느린 쿼리 진단 및 해결
pattern_id: P-10
error_ids: [E-28, E-29, E-30]
tech_scope: 데이터베이스 성능, EXPLAIN, 인덱스
---

# 느린 쿼리 진단 및 해결

데이터베이스 쿼리 성능을 진단하고 최적화합니다.

## 1단계: 증상 고정

증상:
- "Database query timeout" 오류
- 쿼리 실행 시간이 5초 이상
- 데이터베이스 CPU 사용률 높음
- 동시 접속 사용자 증가 시 응답 느림
- 특정 페이지나 기능이 느림

## 2단계: 재현

```sql
-- 느린 쿼리 확인
SHOW VARIABLES LIKE 'slow_query_log';

-- slow query log 활성화
SET GLOBAL slow_query_log = 'ON';
SET GLOBAL long_query_time = 2;

-- 또는 직접 쿼리 실행 시간 측정
\timing ON -- psql
EXPLAIN ANALYZE SELECT * FROM posts WHERE author_id = 1;
```

## 3단계: 범위 축소

느린 쿼리의 원인:

1. **인덱스 부재**: WHERE 절의 컬럼에 인덱스 없음
2. **부적절한 조인**: 큰 테이블 끼리 조인
3. **전체 테이블 스캔**: 필터링 없는 조회
4. **서브쿼리 오버헤드**: 비효율적인 서브쿼리
5. **통계 오래됨**: 쿼리 계획 최적화 안 됨

## 4단계: 증거 수집

```sql
-- PostgreSQL에서 쿼리 실행 계획 분석
EXPLAIN ANALYZE SELECT * FROM posts WHERE author_id = 1;

-- 예상되는 출력:
-- Seq Scan on posts  (cost=0.00..35.50 rows=1 width=100)
-- Filter: (author_id = 1)
-- Planning Time: 0.089 ms
-- Execution Time: 0.234 ms

-- 만약 Seq Scan이면 인덱스가 필요
```

```sql
-- MySQL에서 쿼리 실행 계획
EXPLAIN SELECT * FROM posts WHERE author_id = 1;

-- ANALYZE로 더 자세한 정보
EXPLAIN FORMAT=JSON SELECT * FROM posts WHERE author_id = 1;
```

## 5단계: 원인 후보 정렬

| 원인 | 확률 | 해결 난도 |
|------|------|---------|
| 인덱스 부재 | 매우높음 | 낮음 |
| 부적절한 WHERE 절 | 높음 | 중간 |
| N+1 쿼리 | 높음 | 중간 |
| 데이터 양 증가 | 중간 | 낮음 |
| 통계 오래됨 | 낮음 | 낮음 |

## 6단계: 수정안 선택

### 수정안 1: 인덱스 추가 (가장 일반적)

```sql
-- 단일 컬럼 인덱스
CREATE INDEX idx_posts_author_id ON posts(author_id);

-- 복합 인덱스 (자주 함께 검색되는 컬럼)
CREATE INDEX idx_posts_author_published ON posts(author_id, published);

-- 정렬 포함 인덱스
CREATE INDEX idx_posts_created_desc ON posts(created_at DESC);

-- 부분 인덱스 (특정 조건만)
CREATE INDEX idx_posts_published ON posts(id)
WHERE published = true;

-- 인덱스 확인
SELECT * FROM pg_indexes WHERE tablename = 'posts';
```

```prisma
// Prisma 스키마에 인덱스 정의
model Post {
  id Int @id @default(autoincrement())
  title String
  content String?
  authorId Int
  published Boolean @default(false)
  createdAt DateTime @default(now())

  author User @relation(fields: [authorId], references: [id])

  // 인덱스 정의
  @@index([authorId])
  @@index([authorId, published])
  @@index([createdAt(sort: Desc)])
}
```

### 수정안 2: 쿼리 최적화

```sql
-- ❌ 느린 쿼리: 전체 스캔
SELECT * FROM posts WHERE author_id = 1;

-- ✅ 개선: 필요한 컬럼만 선택
SELECT id, title, created_at FROM posts WHERE author_id = 1;

-- ❌ 느린 쿼리: 부적절한 조인
SELECT * FROM posts
WHERE user_id IN (SELECT id FROM users WHERE status = 'active');

-- ✅ 개선: INNER JOIN
SELECT p.* FROM posts p
INNER JOIN users u ON p.user_id = u.id
WHERE u.status = 'active';

-- ❌ 느린 쿼리: OR 조건 많음
SELECT * FROM posts
WHERE author_id = 1 OR author_id = 2 OR author_id = 3;

-- ✅ 개선: IN 절
SELECT * FROM posts WHERE author_id IN (1, 2, 3);
```

### 수정안 3: EXPLAIN 분석 및 개선

```sql
-- 1단계: 쿼리 실행 계획 확인
EXPLAIN ANALYZE
SELECT p.*, u.name FROM posts p
JOIN users u ON p.author_id = u.id
WHERE p.created_at > '2024-01-01';

-- 결과 분석
-- → Seq Scan on posts (느림)
-- → Hash Join on users (비효율적)

-- 2단계: 인덱스 추가
CREATE INDEX idx_posts_created_at ON posts(created_at);

-- 3단계: 다시 실행 계획 확인
EXPLAIN ANALYZE
SELECT p.*, u.name FROM posts p
JOIN users u ON p.author_id = u.id
WHERE p.created_at > '2024-01-01';

-- 결과
-- → Index Scan on posts (빠름)
-- → Nested Loop (효율적)
```

### 수정안 4: 쿼리 캐싱

```javascript
// Prisma에서 쿼리 캐싱
const redis = require('redis').createClient();

async function getPostsByAuthor(authorId, useCache = true) {
  const cacheKey = `posts:author:${authorId}`;

  if (useCache) {
    const cached = await redis.get(cacheKey);
    if (cached) {
      return JSON.parse(cached);
    }
  }

  const posts = await prisma.post.findMany({
    where: { authorId },
    orderBy: { createdAt: 'desc' }
  });

  await redis.setex(cacheKey, 3600, JSON.stringify(posts));

  return posts;
}
```

### 수정안 5: 페이지네이션

```javascript
// ❌ 느린 쿼리: 모든 데이터 로드
const allPosts = await prisma.post.findMany({
  where: { published: true }
});

// ✅ 페이지네이션
async function getPaginatedPosts(page = 1, pageSize = 20) {
  const skip = (page - 1) * pageSize;

  const [posts, total] = await Promise.all([
    prisma.post.findMany({
      where: { published: true },
      orderBy: { createdAt: 'desc' },
      skip,
      take: pageSize
    }),
    prisma.post.count({
      where: { published: true }
    })
  ]);

  return {
    posts,
    pagination: {
      page,
      pageSize,
      total,
      pages: Math.ceil(total / pageSize)
    }
  };
}
```

### 수정안 6: 집계 함수 활용

```sql
-- ❌ 느린 쿼리: 클라이언트에서 집계
SELECT * FROM comments WHERE post_id = 1;
-- 클라이언트에서 COUNT, SUM, AVG 계산

-- ✅ 데이터베이스에서 집계
SELECT
  COUNT(*) as total_comments,
  AVG(rating) as avg_rating,
  MAX(created_at) as latest_comment
FROM comments
WHERE post_id = 1;
```

### 수정안 7: 배치 작업 분산

```javascript
// ❌ 느린: 모든 데이터 한 번에 처리
const allPosts = await prisma.post.findMany();
for (const post of allPosts) {
  await processPost(post);
}

// ✅ 배치: 작은 단위로 처리
async function processBatch(batchSize = 100) {
  let skip = 0;

  while (true) {
    const posts = await prisma.post.findMany({
      skip,
      take: batchSize
    });

    if (posts.length === 0) break;

    await Promise.all(posts.map(post => processPost(post)));

    skip += batchSize;
  }
}
```

## 7단계: 검증

```javascript
// 쿼리 성능 측정
async function measureQueryPerformance() {
  const startTime = Date.now();

  const posts = await prisma.post.findMany({
    where: { published: true },
    take: 20
  });

  const executionTime = Date.now() - startTime;

  console.log(`Query executed in ${executionTime}ms`);
  console.log(`Retrieved ${posts.length} posts`);

  // 목표: < 100ms
  expect(executionTime).toBeLessThan(100);
}
```

## 8단계: 재발 방지

1. **쿼리 모니터링**

```javascript
prisma.$on('query', (e) => {
  if (e.duration > 1000) {
    console.warn(`Slow query (${e.duration}ms): ${e.query}`);

    // 모니터링 서비스로 전송
    sendAlert({
      type: 'SLOW_QUERY',
      duration: e.duration,
      query: e.query
    });
  }
});
```

2. **정기 인덱스 검토**

```sql
-- 사용되지 않는 인덱스 찾기
SELECT schemaname, tablename, indexname
FROM pg_indexes
WHERE schemaname NOT IN ('pg_catalog', 'information_schema')
ORDER BY tablename, indexname;
```

3. **통계 업데이트**

```sql
-- PostgreSQL
ANALYZE;

-- MySQL
ANALYZE TABLE posts;
```

## 연결된 프롬프트 블록

- **PB-CL-11-index-design**: 인덱스 설계
- **PB-RP-10-query-profiling**: 쿼리 프로파일링
- **PB-DG-11-execution-plan**: 실행 계획 분석
- **PB-PA-11-query-tuning**: 쿼리 튜닝
- **PB-VF-10-perf-monitoring**: 성능 모니터링

content.F-11:
---
id: F-11
title: 커넥션 풀 고갈 해결
pattern_id: P-11
error_ids: [E-31, E-32, E-33]
tech_scope: 데이터베이스 연결, 커넥션 풀, Prisma
---

# 커넥션 풀 고갈 해결

데이터베이스 커넥션 풀이 고갈되어 새로운 연결을 받을 수 없는 문제를 해결합니다.

## 1단계: 증상 고정

오류 메시지:
- "ConnectionError: connect ECONNREFUSED"
- "KnexTimeoutError: Knex: Timeout acquiring a connection. The pool is probably full"
- "FATAL: too many connections"
- "could not connect to server"
- 비정상적으로 느린 데이터베이스 응답

## 2단계: 재현

```javascript
// ❌ 커넥션 누수 예제
// Prisma 클라이언트를 여러 번 인스턴스화
for (let i = 0; i < 100; i++) {
  const prisma = new PrismaClient();
  // 연결하지만 해제하지 않음 → 풀 고갈
}

// ❌ 연결 미해제
const connection = await db.getConnection();
// disconnect() 호출 안 함

// ❌ 오류 시 연결 미해제
try {
  const data = await query();
} catch (error) {
  // 오류 발생 시에도 연결 반환해야 함
}
```

## 3단계: 범위 축소

커넥션 풀 문제의 유형:

1. **커넥션 누수**: 사용 후 반환하지 않음
2. **과다 생성**: 풀 크기보다 많은 요청
3. **타임아웃 짧음**: 연결 타임아웃 설정이 너무 짧음
4. **데드락**: 연결이 블로킹됨
5. **재연결 실패**: 연결 끊김 후 재연결 실패

## 4단계: 증거 수집

```sql
-- PostgreSQL: 현재 연결 수 확인
SELECT count(*) FROM pg_stat_activity;

-- 상세 정보
SELECT usename, application_name, state, query_start FROM pg_stat_activity;

-- 유휴 연결 찾기
SELECT * FROM pg_stat_activity WHERE state = 'idle';

-- MySQL: 현재 연결 수
SHOW PROCESSLIST;

-- 최대 연결 수
SHOW VARIABLES LIKE 'max_connections';
```

```javascript
// Prisma에서 커넥션 풀 상태 확인
const prisma = new PrismaClient({
  log: ['query', 'warn', 'error']
});

// 메트릭 수집
setInterval(async () => {
  const result = await prisma.$queryRaw`
    SELECT count(*) FROM pg_stat_activity
  `;
  console.log('Active connections:', result);
}, 10000);
```

## 5단계: 원인 후보 정렬

| 원인 | 확률 | 복잡도 |
|------|------|--------|
| 연결 미해제 | 매우높음 | 중간 |
| 풀 크기 너무 작음 | 높음 | 낮음 |
| 동시 요청 많음 | 높음 | 중간 |
| 쿼리 타임아웃 | 중간 | 낮음 |
| 데드락 | 중간 | 높음 |

## 6단계: 수정안 선택

### 수정안 1: Prisma 클라이언트 싱글톤

```javascript
// ❌ 잘못된 사용: 매번 새 인스턴스 생성
app.get('/api/users', async (req, res) => {
  const prisma = new PrismaClient(); // 매번 새 인스턴스!
  const users = await prisma.user.findMany();
  await prisma.$disconnect();
  res.json(users);
});

// ✅ 올바른 사용: 싱글톤 인스턴스
// lib/prisma.ts
import { PrismaClient } from '@prisma/client';

const globalForPrisma = global as unknown as { prisma: PrismaClient };

export const prisma =
  globalForPrisma.prisma ||
  new PrismaClient({
    log: process.env.NODE_ENV === 'development'
      ? ['query', 'error', 'warn']
      : ['error']
  });

if (process.env.NODE_ENV !== 'production')
  globalForPrisma.prisma = prisma;

// app.ts
import { prisma } from './lib/prisma';

app.get('/api/users', async (req, res) => {
  const users = await prisma.user.findMany();
  res.json(users);
});

// 애플리케이션 종료 시 정리
process.on('SIGINT', async () => {
  await prisma.$disconnect();
  process.exit(0);
});
```

### 수정안 2: 커넥션 풀 크기 조정

```javascript
// .env
DATABASE_URL="postgresql://user:pass@localhost:5432/db?schema=public"

// 풀 크기 설정 (기본: 2, 최대: 10)
DATABASE_URL="postgresql://user:pass@localhost:5432/db?schema=public&connection_limit=5&pool_timeout=5"
```

```javascript
// 프로그래밍으로 설정
const prisma = new PrismaClient({
  datasources: {
    db: {
      url: process.env.DATABASE_URL + '?connection_limit=5'
    }
  }
});
```

### 수정안 3: 연결 타임아웃 및 재시도

```javascript
// PgBouncer 또는 데이터베이스 풀러 사용 (권장)
// pgbouncer.ini
[databases]
mydb = host=localhost port=5432 dbname=mydb

[pgbouncer]
pool_mode = transaction
max_client_conn = 1000
default_pool_size = 25
min_pool_size = 10
reserve_pool_size = 5
reserve_pool_timeout = 3
```

### 수정안 4: 오류 처리 및 재시도 로직

```javascript
// retry 라이브러리 사용
import pRetry from 'p-retry';

async function queryWithRetry() {
  return pRetry(
    async () => {
      return await prisma.user.findMany();
    },
    {
      retries: 3,
      minTimeout: 100,
      maxTimeout: 1000,
      onFailedAttempt: error => {
        console.warn(
          `Attempt ${error.attemptNumber} failed. ` +
          `${error.retriesLeft} retries left. ` +
          `Error: ${error.message}`
        );
      }
    }
  );
}
```

### 수정안 5: 요청 큐 및 속도 제한

```javascript
// 동시 요청 수 제한
import PQueue from 'p-queue';

const queue = new PQueue({
  concurrency: 5, // 동시에 5개 요청만 처리
  interval: 1000,
  intervalCap: 20 // 초당 최대 20개 요청
});

app.get('/api/users', async (req, res) => {
  try {
    const users = await queue.add(() =>
      prisma.user.findMany()
    );
    res.json(users);
  } catch (error) {
    res.status(503).json({ error: 'Service unavailable' });
  }
});
```

### 수정안 6: 커넥션 모니터링

```javascript
// 주기적으로 커넥션 상태 확인
async function monitorConnections() {
  setInterval(async () => {
    try {
      const result = await prisma.$queryRaw`
        SELECT count(*) as active_connections FROM pg_stat_activity
      `;

      const count = result[0].active_connections;
      const limit = 100; // 최대 커넥션

      if (count > limit * 0.8) {
        console.warn(`Connection pool near capacity: ${count}/${limit}`);
        // 알럿 발송
        sendAlert({
          type: 'CONNECTION_POOL_NEAR_CAPACITY',
          current: count,
          limit: limit
        });
      }
    } catch (error) {
      console.error('Failed to monitor connections:', error);
    }
  }, 30000); // 30초마다 확인
}

monitorConnections();
```

### 수정안 7: 유휴 연결 정리

```javascript
// 유휴 연결 강제 종료 (PostgreSQL)
// pgbouncer 설정
[pgbouncer]
server_lifetime = 3600
server_idle_timeout = 600 # 10분 유휴 후 정리
idle_in_transaction_session_timeout = 300 # 5분 유휴 트랜잭션 정리
```

## 7단계: 검증

```javascript
describe('Connection Pool', () => {
  it('should reuse connections', async () => {
    const results = await Promise.all([
      prisma.user.findFirst(),
      prisma.user.findFirst(),
      prisma.user.findFirst()
    ]);

    // 3개 요청이지만 1-2개 커넥션만 사용됨
    expect(results).toHaveLength(3);
  });

  it('should handle concurrent requests', async () => {
    const requests = Array(100).fill(null).map(() =>
      prisma.user.findMany({ take: 1 })
    );

    const results = await Promise.all(requests);

    expect(results).toHaveLength(100);
  });

  it('should disconnect properly on process termination', async () => {
    await prisma.$disconnect();

    // 재연결 확인
    const user = await prisma.user.findFirst();
    expect(user).toBeDefined();
  });
});
```

## 8단계: 재발 방지

1. **체크리스트**
   - [ ] PrismaClient는 싱글톤 인스턴스인가?
   - [ ] 모든 연결이 올바르게 해제되는가?
   - [ ] 커넥션 풀 크기가 적절한가?
   - [ ] 비정상 종료 시 정리 코드 있는가?

2. **모니터링**

```javascript
// Prometheus 메트릭으로 수집
import prometheus from 'prom-client';

const activeConnections = new prometheus.Gauge({
  name: 'database_active_connections',
  help: 'Number of active database connections'
});

setInterval(async () => {
  const result = await prisma.$queryRaw`
    SELECT count(*) FROM pg_stat_activity
  `;
  activeConnections.set(result[0].count);
}, 10000);
```

## 연결된 프롬프트 블록

- **PB-CL-12-connection-pool**: 커넥션 풀 개념
- **PB-RP-11-pool-stress**: 풀 스트레스 테스트
- **PB-DG-12-connection-trace**: 연결 추적
- **PB-PA-12-pool-config**: 풀 설정 최적화
- **PB-VF-11-pool-monitor**: 풀 모니터링

content.F-12:
---
id: F-12
title: 락/데드락 해결
pattern_id: P-12
error_ids: [E-34, E-35, E-36]
tech_scope: 트랜잭션, 동시성, 데이터베이스 락
---

# 락/데드락 해결

데이터베이스 락으로 인한 성능 저하와 데드락 문제를 해결합니다.

## 1단계: 증상 고정

- "Deadlock detected" 오류
- "Lock timeout exceeded"
- 특정 쿼리가 무한 대기
- "waiting for ..." 상태
- 임의로 트랜잭션 실패

## 2단계: 재현

```javascript
// ❌ 데드락 시나리오
// Transaction 1: UPDATE user SET balance = 100 WHERE id = 1; UPDATE user SET balance = 200 WHERE id = 2;
// Transaction 2: UPDATE user SET balance = 300 WHERE id = 2; UPDATE user SET balance = 400 WHERE id = 1;
// → 두 트랜잭션이 서로 다른 행에 락을 잡고 대기 = 데드락

await prisma.$transaction(async (tx) => {
  await tx.user.update({
    where: { id: 1 },
    data: { balance: 100 }
  });

  // 다른 트랜잭션이 동시에 같은 행 수정 시도
  // → 락 대기 → 데드락 가능성
  await tx.user.update({
    where: { id: 2 },
    data: { balance: 200 }
  });
});
```

## 3단계: 범위 축소

락/데드락 유형:

1. **쓰기 락(Write Lock)**: UPDATE/DELETE 시 발생
2. **읽기 락(Read Lock)**: FOR UPDATE로 명시적 락
3. **행 수준 락**: 특정 행 락
4. **테이블 수준 락**: 전체 테이블 락
5. **시퀀셜 락**: 순서 의존성으로 인한 락

## 4단계: 증거 수집

```sql
-- PostgreSQL: 현재 락 상태 확인
SELECT pid, usename, query, wait_event_type, wait_event
FROM pg_stat_activity WHERE wait_event_type IS NOT NULL;

-- 데드락 로그 확인
SELECT * FROM pg_stat_statements WHERE query LIKE '%deadlock%';

-- 블로킹 쿼리 찾기
SELECT blocked_locks.pid AS blocked_pid,
       blocked_activity.usename AS blocked_user,
       blocking_locks.pid AS blocking_pid,
       blocking_activity.usename AS blocking_user,
       blocked_activity.query AS blocked_statement,
       blocking_activity.query AS blocking_statement
FROM pg_catalog.pg_locks blocked_locks
JOIN pg_catalog.pg_stat_activity blocked_activity ON blocked_activity.pid = blocked_locks.pid
JOIN pg_catalog.pg_locks blocking_locks ON blocking_locks.locktype = blocked_locks.locktype
  AND blocking_locks.database IS NOT DISTINCT FROM blocked_locks.database
  AND blocking_locks.relation IS NOT DISTINCT FROM blocked_locks.relation
  AND blocking_locks.page IS NOT DISTINCT FROM blocked_locks.page
  AND blocking_locks.tuple IS NOT DISTINCT FROM blocked_locks.tuple
  AND blocking_locks.virtualxid IS NOT DISTINCT FROM blocked_locks.virtualxid
  AND blocking_locks.transactionid IS NOT DISTINCT FROM blocked_locks.transactionid
  AND blocking_locks.classid IS NOT DISTINCT FROM blocked_locks.classid
  AND blocking_locks.objid IS NOT DISTINCT FROM blocked_locks.objid
  AND blocking_locks.objsubid IS NOT DISTINCT FROM blocked_locks.objsubid
  AND blocking_locks.pid != blocked_locks.pid
JOIN pg_catalog.pg_stat_activity blocking_activity ON blocking_activity.pid = blocking_locks.pid
WHERE NOT blocked_locks.granted;
```

## 5단계: 원인 후보 정렬

| 원인 | 확률 | 복잡도 |
|------|------|--------|
| 트랜잭션 순서 불일치 | 매우높음 | 중간 |
| 긴 트랜잭션 | 높음 | 중간 |
| 암시적 락 | 높음 | 낮음 |
| 부적절한 격리 수준 | 중간 | 높음 |

## 6단계: 수정안 선택

### 수정안 1: 트랜잭션 순서 정렬

```javascript
// ❌ 데드락 위험
async function transfer(fromId, toId, amount) {
  await prisma.$transaction(async (tx) => {
    if (fromId < toId) {
      // 트랜잭션 1
      await tx.account.update({ where: { id: fromId }, data: { balance: { decrement: amount } } });
      await tx.account.update({ where: { id: toId }, data: { balance: { increment: amount } } });
    } else {
      // 트랜잭션 2 (순서 반대)
      await tx.account.update({ where: { id: toId }, data: { balance: { increment: amount } } });
      await tx.account.update({ where: { id: fromId }, data: { balance: { decrement: amount } } });
    }
  });
}

// ✅ 데드락 방지: 항상 작은 ID부터 접근
async function transfer(fromId, toId, amount) {
  const [id1, id2] = fromId < toId ? [fromId, toId] : [toId, fromId];

  await prisma.$transaction(async (tx) => {
    const account1 = await tx.account.findUnique({ where: { id: id1 } });
    const account2 = await tx.account.findUnique({ where: { id: id2 } });

    if (id1 === fromId) {
      // fromId가 작은 ID
      await tx.account.update({ where: { id: fromId }, data: { balance: { decrement: amount } } });
      await tx.account.update({ where: { id: toId }, data: { balance: { increment: amount } } });
    } else {
      // toId가 작은 ID
      await tx.account.update({ where: { id: toId }, data: { balance: { increment: amount } } });
      await tx.account.update({ where: { id: fromId }, data: { balance: { decrement: amount } } });
    }
  });
}
```

### 수정안 2: 격리 수준 조정

```javascript
// 트랜잭션 격리 수준 설정
await prisma.$transaction(
  async (tx) => {
    // 쿼리 실행
    return await tx.user.findMany();
  },
  {
    isolationLevel: 'ReadCommitted' // 기본값
    // 옵션: Serializable, RepeatableRead, ReadCommitted, ReadUncommitted
  }
);
```

```sql
-- PostgreSQL: 세션 격리 수준 설정
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
SET TRANSACTION ISOLATION LEVEL REPEATABLE READ;
SET TRANSACTION ISOLATION LEVEL READ COMMITTED; -- 기본값
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED; -- PostgreSQL에서는 READ COMMITTED와 동일
```

### 수정안 3: FOR UPDATE로 명시적 락

```javascript
// ✅ 명시적 락으로 순서 보장
async function transfer(fromId, toId, amount) {
  await prisma.$transaction(async (tx) => {
    // 두 계정을 명시적으로 락 (작은 ID부터)
    const [id1, id2] = fromId < toId ? [fromId, toId] : [toId, fromId];

    const account1 = await tx.$queryRaw`
      SELECT * FROM accounts WHERE id = ${id1} FOR UPDATE
    `;

    const account2 = await tx.$queryRaw`
      SELECT * FROM accounts WHERE id = ${id2} FOR UPDATE
    `;

    // 잔액 확인 및 업데이트
    if (account1.balance >= amount) {
      await tx.account.update({
        where: { id: fromId },
        data: { balance: { decrement: amount } }
      });

      await tx.account.update({
        where: { id: toId },
        data: { balance: { increment: amount } }
      });
    } else {
      throw new Error('Insufficient balance');
    }
  });
}
```

### 수정안 4: 타임아웃 설정

```javascript
// 트랜잭션 타임아웃
await prisma.$transaction(
  async (tx) => {
    return await tx.user.findMany();
  },
  {
    timeout: 5000 // 5초 타임아웃
  }
);

// 또는 쿼리 수준 타임아웃
await prisma.$queryRaw`
  SET statement_timeout = 5000;
  SELECT * FROM users;
`;
```

### 수정안 5: 재시도 로직

```javascript
import pRetry from 'p-retry';

async function executeWithRetry(transaction) {
  return pRetry(
    () => transaction(),
    {
      retries: 3,
      minTimeout: 100,
      maxTimeout: 1000,
      onFailedAttempt: error => {
        if (error.message.includes('Deadlock')) {
          console.warn('Deadlock detected, retrying...');
        }
      }
    }
  );
}

// 사용
await executeWithRetry(async () => {
  return await prisma.$transaction(async (tx) => {
    // 트랜잭션 로직
  });
});
```

### 수정안 6: 낙관적 락(Optimistic Locking)

```javascript
// Prisma 스키마에 version 필드 추가
model Account {
  id Int @id
  balance Decimal
  version Int @default(0)
}

// 낙관적 락으로 충돌 감지
async function updateBalance(id, newBalance) {
  const account = await prisma.account.findUnique({ where: { id } });

  try {
    const updated = await prisma.account.update({
      where: { id },
      data: {
        balance: newBalance,
        version: { increment: 1 }
      }
    });

    return updated;
  } catch (error) {
    if (error.code === 'P2025') {
      // 충돌 발생: version이 변경됨
      throw new Error('Version mismatch - concurrent update detected');
    }
    throw error;
  }
}
```

## 7단계: 검증

```javascript
// 동시성 테스트
describe('Deadlock Prevention', () => {
  it('should not deadlock on concurrent transfers', async () => {
    const [account1, account2] = [1, 2];
    const amount = 10;

    const results = await Promise.all([
      transfer(account1, account2, amount),
      transfer(account2, account1, amount)
    ]);

    expect(results).toHaveLength(2);
    expect(results[0]).toBeDefined();
    expect(results[1]).toBeDefined();
  });

  it('should handle concurrent updates', async () => {
    const updates = Array(50).fill(null).map((_, i) =>
      prisma.account.update({
        where: { id: 1 },
        data: { balance: { increment: 1 } }
      })
    );

    const results = await Promise.allSettled(updates);

    const successful = results.filter(r => r.status === 'fulfilled');
    expect(successful.length).toBeGreaterThan(0);
  });
});
```

## 8단계: 재발 방지

1. **코드 리뷰 체크리스트**
   - [ ] 여러 행/테이블을 수정하는 트랜잭션인가?
   - [ ] 액세스 순서가 일관적인가?
   - [ ] 트랜잭션 범위가 최소인가?

2. **모니터링**

```javascript
// 데드락 감시
prisma.$on('query', (event) => {
  if (event.query.includes('ROLLBACK') && event.query.includes('deadlock')) {
    console.error('Deadlock occurred:', event.query);
    sendAlert({ type: 'DEADLOCK' });
  }
});
```

## 연결된 프롬프트 블록

- **PB-CL-13-transactions**: 트랜잭션 이해
- **PB-RP-12-concurrency**: 동시성 테스트
- **PB-DG-13-lock-trace**: 락 추적
- **PB-PA-13-transaction-opt**: 트랜잭션 최적화
- **PB-VF-12-deadlock-test**: 데드락 테스트

